    "id": "youmind-zh-25619",
    "prompt": "type: image_generation_prompt\n\n{\n  \"title\": \"2026 年 FIFA 世界杯“全力以赴”通用海报\",\n  \"aspect_ratio\": \"9:16\",\n  \"style\": \"超写实电影感体育海报\",\n  \"quality\": \"16K UHD 极致写实\",\n  \"subject\": {\n    \"identity\": \"{argument name=\"player name\" default=\"[球员姓名或上传的球员]\"}\",\n    \"pose\": \"强有力的侧面肖像，神情专注\",\n    \"expression\": \"坚定、全力以赴、冠军心态\",\n    \"gesture\": \"单手紧握队徽附近的国家队球衣\"\n  },\n  \"wardrobe\": {\n    \"kit\": \"{argument name=\"country\" default=\"[国家名称]\"} 官方主场球衣\",\n    \"details\": \"真实的纹理、足协徽章、官方 2026 年 FIFA 世界杯袖标、逼真的布料褶皱和缝线\"\n  },\n  \"environment\": {\n    \"background\": \"干净的浅灰色质感体育海报画布，带有未来感的几何线条、精致的技术图形和高级编辑排版\",\n    \"effects\": \"动态油漆飞溅、能量条和粒子效果，灵感源自 {argument name=\"national colors\" default=\"[国家名称]\"} 的国家代表色\",\n    \"national_elements\": \"灵感源自国家特征的细微星形、符号和图形图案\",\n    \"atmosphere\": \"高能的赛事期待感\"\n  },\n  \"lighting\": {\n    \"type\": \"戏剧性电影布光\",\n    \"rim_light\": \"与国旗颜色相呼应的彩色轮廓光\",\n    \"highlights\": \"光泽的皮肤反射和逼真的汗水细节\",\n    \"contrast\": \"强烈的体育海报对比度\"\n  },\n  \"composition\": {\n    \"camera_angle\": \"侧面特写\",\n    \"framing\": \"上半身肖像\",\n    \"depth_of_field\": \"浅景深\",\n    \"focus\": \"面部、队徽和抓握球衣的手\"\n  },\n  \"branding\": {\n    \"tournament\": \"2026 年 FIFA 世界杯\",\n    \"logo\": \"优雅融入官方 2026 年 FIFA 世界杯标志\",\n    \"color_palette\": \"官方 2026 年 FIFA 世界杯赛事配色与 [国家名称] 国家代表色相结合\",\n    \"headline\": \"\\\"LOCKED IN\\\"（全力以赴）采用大型现代字体显示\",\n    \"subtitle\": \"[国家名称] • 2026 年 FIFA 世界杯\"\n  },\n  \"mood\": [\n    \"专注\",\n    \"精英\",\n    \"无畏\",\n    \"民族自豪感\",\n    \"冠军能量\"\n  ],\n  \"camera\": {\n    \"lens\": \"85mm\",\n    \"sharpness\": \"极致细节\",\n    \"rendering\": \"超写实体育插画与高级编辑海报设计相结合\"\n  },\n  \"output_goal\": \"创作一张世界级的 2026 年 FIFA 世界杯海报，适用于任何球员和任何国家。海报采用侧面肖像、抓握球衣动作、爆炸性的国家代表色能量特效、优雅的赛事品牌元素，营造出足以媲美官方宣传活动的强大“全力以赴”氛围。\"\n}",
    "author": "Saul Goodman",
